import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs"
import { dirname } from "node:path"
import { getVersion } from "./utils.js"

const CAST_AI_MODELS_API = "https://api.cast.ai/v1/llm/openai/models?providerName=AI%20Enabler"
const CAST_AI_LLM_BASE_URL = "https://llm.kimchi.dev/openai/v1"
const FETCH_TIMEOUT_MS = 5000

const EXCLUDED_MODEL_PATTERNS = [/^smoll/i, /^qwen/i]

function filterAndSortModels(models: string[]): string[] {
	return models.filter((id) => !EXCLUDED_MODEL_PATTERNS.some((re) => re.test(id))).sort((a, b) => a.localeCompare(b))
}

interface CastAIModelsResponse {
	models: string[]
}

function modelIdToName(id: string): string {
	return id
		.split(/[-_]/)
		.map((part) => part.charAt(0).toUpperCase() + part.slice(1))
		.join(" ")
}

async function fetchAvailableModels(apiKey: string): Promise<string[]> {
	const response = await fetch(CAST_AI_MODELS_API, {
		headers: { Authorization: `Bearer ${apiKey}` },
		signal: AbortSignal.timeout(FETCH_TIMEOUT_MS),
	})
	if (!response.ok) {
		throw new Error(`Failed to fetch models: ${response.status} ${response.statusText}`)
	}
	const body = await response.json()
	if (!body || typeof body !== "object" || !Array.isArray(body.models)) {
		throw new Error("Unexpected response shape from models API")
	}
	return (body as CastAIModelsResponse).models
}

function buildModelsConfig(models: string[]) {
	return {
		providers: {
			"kimchi-dev": {
				baseUrl: CAST_AI_LLM_BASE_URL,
				apiKey: "KIMCHI_API_KEY",
				api: "openai-completions",
				authHeader: true,
				headers: { "User-Agent": `kimchi/${getVersion()}` },
				models: models.map((id) => ({
					id,
					name: modelIdToName(id),
					reasoning: false,
					input: ["text"],
					contextWindow: 131072,
					maxTokens: 16384,
					cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
				})),
			},
		},
	}
}

/**
 * The default models.json configuration for the Cast AI provider.
 * Models are registered with the "kimchi-dev" provider name. The apiKey field
 * references the KIMCHI_API_KEY environment variable, which is set by the
 * CLI entry point from the resolved kimchi config before pi-mono imports.
 */
const DEFAULT_MODELS_CONFIG = {
	providers: {
		"kimchi-dev": {
			baseUrl: CAST_AI_LLM_BASE_URL,
			apiKey: "KIMCHI_API_KEY",
			api: "openai-completions",
			authHeader: true,
			headers: { "User-Agent": `kimchi/${getVersion()}` },
			models: [
				{
					id: "kimi-k2.5",
					name: "Kimi K2.5",
					reasoning: false,
					input: ["text"],
					contextWindow: 131072,
					maxTokens: 16384,
					cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
				},
				{
					id: "glm-5-fp8",
					name: "GLM 5 FP8",
					reasoning: false,
					input: ["text"],
					contextWindow: 131072,
					maxTokens: 16384,
					cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
				},
				{
					id: "minimax-m2.7",
					name: "Minimax M2.7",
					reasoning: true,
					input: ["text"],
					contextWindow: 196608,
					maxTokens: 32768,
					cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
				},
			],
		},
	},
}

export type ModelsConfigResult =
	| { source: "discovered"; models: string[] }
	| { source: "default"; models: string[]; error?: string }

/**
 * Fetch available models from the Cast AI API and write the configuration to
 * modelsJsonPath. Falls back to the static default configuration if the fetch
 * fails. Always overwrites any existing file so the model list stays current
 * on every startup.
 */
export async function updateModelsConfig(modelsJsonPath: string, apiKey: string): Promise<ModelsConfigResult> {
	const dir = dirname(modelsJsonPath)
	mkdirSync(dir, { recursive: true })

	try {
		const fetched = await fetchAvailableModels(apiKey)
		const models = filterAndSortModels(fetched)
		if (models.length > 0) {
			writeFileSync(modelsJsonPath, JSON.stringify(buildModelsConfig(models), null, "\t"), "utf-8")
			return { source: "discovered", models }
		}
		writeFileSync(modelsJsonPath, JSON.stringify(DEFAULT_MODELS_CONFIG, null, "\t"), "utf-8")
		return {
			source: "default",
			models: DEFAULT_MODELS_CONFIG.providers["kimchi-dev"].models.map((m) => m.id),
			error: fetched.length === 0 ? "API returned empty model list" : "API returned no usable models after filtering",
		}
	} catch (err) {
		writeFileSync(modelsJsonPath, JSON.stringify(DEFAULT_MODELS_CONFIG, null, "\t"), "utf-8")
		return {
			source: "default",
			models: DEFAULT_MODELS_CONFIG.providers["kimchi-dev"].models.map((m) => m.id),
			error: err instanceof Error ? err.message : String(err),
		}
	}
}

/**
 * Check whether the models.json at the given path already contains a "kimchi-dev" provider.
 */
export function hasKimchiProvider(modelsJsonPath: string): boolean {
	if (!existsSync(modelsJsonPath)) {
		return false
	}
	try {
		const raw = readFileSync(modelsJsonPath, "utf-8")
		const config = JSON.parse(raw)
		return config?.providers?.["kimchi-dev"] !== undefined
	} catch {
		return false
	}
}

import type { AssistantMessage } from "@mariozechner/pi-ai"
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent"
import type { TelemetryConfig } from "../config.js"

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function nowNano(): string {
	return String(Date.now() * 1_000_000)
}

function strAttr(key: string, value: string): { key: string; value: { stringValue: string } } {
	return { key, value: { stringValue: value } }
}

function inferLanguage(filePath: string): string {
	const ext = filePath.split(".").pop()?.toLowerCase() ?? ""
	const map: Record<string, string> = {
		ts: "TypeScript",
		tsx: "TypeScript",
		js: "JavaScript",
		jsx: "JavaScript",
		mjs: "JavaScript",
		cjs: "JavaScript",
		py: "Python",
		go: "Go",
		rs: "Rust",
		rb: "Ruby",
		java: "Java",
		kt: "Kotlin",
		swift: "Swift",
		c: "C",
		h: "C",
		cpp: "C++",
		cc: "C++",
		cxx: "C++",
		hpp: "C++",
		cs: "C#",
		php: "PHP",
		dart: "Dart",
		md: "Markdown",
		mdx: "Markdown",
		json: "JSON",
		yaml: "YAML",
		yml: "YAML",
		toml: "TOML",
		ini: "TOML",
		xml: "HTML/XML",
		html: "HTML/XML",
		htm: "HTML/XML",
		svg: "HTML/XML",
		css: "CSS",
		scss: "CSS",
		less: "CSS",
		sql: "SQL",
		sh: "Bash",
		bash: "Bash",
		zsh: "Bash",
		txt: "Plain text",
		proto: "Protocol Buffers",
		tf: "HCL",
		dockerfile: "Dockerfile",
	}
	return map[ext] ?? "unknown"
}

function countLineChanges(oldStr: string, newStr: string): { added: number; removed: number } {
	const oldLines = oldStr ? oldStr.split("\n").length : 0
	const newLines = newStr ? newStr.split("\n").length : 0
	if (newLines >= oldLines) return { added: newLines - oldLines, removed: 0 }
	return { added: 0, removed: oldLines - newLines }
}

// ---------------------------------------------------------------------------
// OTLP sender
// ---------------------------------------------------------------------------

async function sendLog(
	config: TelemetryConfig,
	sessionId: string,
	eventName: string,
	attrs: Record<string, string | number>,
): Promise<void> {
	if (!config.enabled || !config.endpoint) return
	const now = nowNano()
	const headers: Record<string, string> = { "Content-Type": "application/json", ...config.headers }
	const payload = {
		resourceLogs: [
			{
				resource: { attributes: [strAttr("service.name", "kimchi")], droppedAttributesCount: 0 },
				scopeLogs: [
					{
						scope: { name: "kimchi", version: "1.0.0" },
						logRecords: [
							{
								timeUnixNano: now,
								observedTimeUnixNano: now,
								severityNumber: 9,
								severityText: "INFO",
								eventName,
								body: { stringValue: eventName },
								attributes: [
									strAttr("session.id", sessionId),
									strAttr("client", "pi"),
									...Object.entries(attrs).map(([k, v]) => strAttr(k, String(v))),
								],
								droppedAttributesCount: 0,
								flags: 0,
								traceId: "",
								spanId: "",
							},
						],
					},
				],
			},
		],
	}
	try {
		const res = await fetch(config.endpoint, {
			method: "POST",
			headers,
			body: JSON.stringify(payload),
		})
		if (!res.ok) {
			console.error(`[telemetry] send failed: ${res.status} ${await res.text()}`)
		}
	} catch (err) {
		console.error(`[telemetry] send error: ${err}`)
	}
}

const TELEMETRY_DRAIN_TIMEOUT_MS = 5_000

// ---------------------------------------------------------------------------
// Extension
// ---------------------------------------------------------------------------

export default function telemetryExtension(config: TelemetryConfig) {
	return (pi: ExtensionAPI) => {
		if (!config.enabled) return

		let sessionId = crypto.randomUUID()
		let sessionStartMs = Date.now()
		const sentMessages = new Set<string>()
		const pendingArgs = new Map<string, { toolName: string; args: unknown }>()
		const inFlight = new Set<Promise<void>>()
		let shuttingDown = false

		function track(p: Promise<void>): void {
			if (shuttingDown) return
			inFlight.add(p)
			p.finally(() => inFlight.delete(p))
		}

		pi.on("session_start", async () => {
			sessionId = crypto.randomUUID()
			sessionStartMs = Date.now()
			sentMessages.clear()
			pendingArgs.clear()
			shuttingDown = false
		})

		pi.on("session_shutdown", async () => {
			shuttingDown = true
			if (inFlight.size === 0) return
			const drain = Promise.allSettled([...inFlight])
			let timer: NodeJS.Timeout | undefined
			const timeout = new Promise<void>((resolve) => {
				timer = setTimeout(resolve, TELEMETRY_DRAIN_TIMEOUT_MS)
			})
			await Promise.race([drain, timeout])
			clearTimeout(timer)
		})

		pi.on("message_end", async (event) => {
			const msg = event.message
			if (msg.role !== "assistant") return
			try {
				const assistant = msg as AssistantMessage
				const msgId = String(assistant.timestamp)
				if (sentMessages.has(msgId)) return
				sentMessages.add(msgId)

				const model = assistant.model ?? "unknown"
				const rawProvider = String(assistant.provider ?? "unknown")
				const provider = rawProvider === "kimchi-dev" ? "ai-enabler" : rawProvider
				const { input, output, cacheRead, cacheWrite } = assistant.usage
				const costTotal = assistant.usage.cost.total
				const sessionUptimeMs = Date.now() - sessionStartMs

				track(
					sendLog(config, sessionId, "api_request", {
						model,
						provider,
						input_tokens: input,
						output_tokens: output,
						cache_read_tokens: cacheRead,
						cache_creation_tokens: cacheWrite,
						cost_usd: costTotal,
						session_uptime_ms: sessionUptimeMs,
					}),
				)
			} catch (err) {
				console.error("[telemetry] message_end handler error:", err)
			}
		})

		pi.on("tool_execution_start", async (event) => {
			pendingArgs.set(event.toolCallId, { toolName: event.toolName, args: event.args })
		})

		pi.on("tool_execution_end", async (event) => {
			const pending = pendingArgs.get(event.toolCallId)
			pendingArgs.delete(event.toolCallId)
			if (!pending) return

			const { toolName, args } = pending as { toolName: string; args: Record<string, unknown> }

			if (toolName === "bash") {
				const command = String(args?.command ?? "")
				if (/git\s+commit\b/.test(command) && !/--dry-run/.test(command)) {
					track(sendLog(config, sessionId, "tool_usage", { tool: "bash", action: "git_commit" }))
				}
				if (/gh\s+pr\s+create\b/.test(command)) {
					track(sendLog(config, sessionId, "tool_usage", { tool: "bash", action: "gh_pr_create" }))
				}
			}

			if (toolName === "edit") {
				const filePath = String(args?.filePath ?? "")
				const language = inferLanguage(filePath)
				const changes = countLineChanges(String(args?.oldString ?? ""), String(args?.newString ?? ""))
				track(
					sendLog(config, sessionId, "tool_usage", {
						tool: "edit",
						language,
						lines_added: changes.added,
						lines_removed: changes.removed,
					}),
				)
			}

			if (toolName === "write") {
				const filePath = String(args?.filePath ?? "")
				const language = inferLanguage(filePath)
				const content = String(args?.content ?? "")
				const lines = content ? content.split("\n").length : 1
				track(
					sendLog(config, sessionId, "tool_usage", {
						tool: "write",
						language,
						lines_added: lines,
					}),
				)
			}

			if (toolName === "multiedit") {
				const filePath = String(args?.filePath ?? "")
				const language = inferLanguage(filePath)
				const edits = Array.isArray(args?.edits)
					? (args.edits as Array<{ oldString?: string; newString?: string }>)
					: []
				for (const edit of edits) {
					const changes = countLineChanges(String(edit.oldString ?? ""), String(edit.newString ?? ""))
					track(
						sendLog(config, sessionId, "tool_usage", {
							tool: "edit",
							language,
							lines_added: changes.added,
							lines_removed: changes.removed,
						}),
					)
				}
			}
		})
	}
}

